    <script>
        (function() {
            function processAndInjectChaData() {
                const rawDataElement = document.getElementById('cha-raw-data');
                const container = document.getElementById('cha-container');
                if (!rawDataElement || !container) return;
                const rawHTML = rawDataElement.innerHTML;
                container.innerHTML = '';
                if (!rawHTML.trim()) {
                    container.innerHTML = `<div class="info-block" style="margin-top: 15px;"><div class="info-block-content" style="text-align: center; color: #b29a9a;">当前没有同行的人，宝宝好像有点孤单呢……</div></div>`;
                    return;
                }
                const chaItems = rawHTML.split(/&lt;cha&gt;|&lt;\/cha&gt;/).filter(item => item.trim() !== '');
                chaItems.forEach(item => {
                    const parts = item.split(/:(.+)/);
                    if (parts.length >= 2) {
                        const name = parts[0].trim();
                        const description = parts[1].trim();
                        const npcBlock = document.createElement('div');
                        npcBlock.innerHTML = `<div class="npc-block-title"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"></path><circle cx="9" cy="7" r="4"></circle></svg><span>${name}</span></div><div class="info-block-content">${description}</div>`;
                        container.appendChild(npcBlock);
                    }
                });
            }
            function initializeStatusBar() {
                setTimeout(processAndInjectChaData, 50);
            }
            initializeStatusBar();
            if (typeof window.changePage !== 'function') {
                window.changePage = function(direction, buttonElement) {
                    const wrapper = buttonElement.closest('.status-bar-wrapper');
                    if (!wrapper) return;
                    const pages = wrapper.querySelectorAll('.page');
                    const indicator = wrapper.querySelector('.page-indicator');
                    let currentPageIndex = -1;
                    pages.forEach((page, index) => { if (page.classList.contains('active')) { currentPageIndex = index; } });
                    if (currentPageIndex === -1) return;
                    pages[currentPageIndex].classList.remove('active');
                    let nextPageIndex = (currentPageIndex + direction + pages.length) % pages.length;
                    pages[nextPageIndex].classList.add('active');
                    indicator.textContent = (nextPageIndex + 1) + ' / ' + pages.length;
                }
            }
        })();
    </script>
